package com.interview.incidentrca.controller;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.exception.BadRequestException;import com.interview.incidentrca.service.AnalyticsService;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequiredArgsConstructor public class AnalyticsController{private final AnalyticsService analytics; @GetMapping("/api/analytics/severity") List<CountResponse> severity(){return analytics.severity();} @GetMapping("/api/analytics/status") List<CountResponse> status(){return analytics.status();} @GetMapping("/api/analytics/top-services") List<CountResponse> top(){return analytics.topServices();} @GetMapping("/api/analytics/sla-breaches") Map<String,Object> sla(){return analytics.slaBreaches();} @GetMapping("/api/audit-logs") @PreAuthorize("hasRole('ADMIN')") Page<AuditLogResponse> audit(@RequestParam(defaultValue="0") int page,@RequestParam(defaultValue="10") int size,@RequestParam(defaultValue="timestamp,desc") String sort){return analytics.audit(pageable(page,size,sort));} private Pageable pageable(int page,int size,String sort){if(page<0)throw new BadRequestException("page must be 0 or greater");if(size<1||size>100)throw new BadRequestException("size must be between 1 and 100");String[] parts=sort.split(",",2);String field=parts[0].trim();Set<String> allowed=Set.of("id","actor","action","timestamp");if(!allowed.contains(field))throw new BadRequestException("sort must be one of "+allowed+" with optional direction, example timestamp,desc");Sort.Direction direction=parts.length>1&&"asc".equalsIgnoreCase(parts[1].trim())?Sort.Direction.ASC:Sort.Direction.DESC;return PageRequest.of(page,size,Sort.by(direction,field));} }
